+}
+
+/// Delta-aware HNSW index
+pub struct DeltaHnsw {
+    /// Configuration
+    config: DeltaHnswConfig,
+    /// Vector dimensions
+    dimensions: usize,
+    /// All nodes
+    nodes: Vec<RwLock<HnswNode>>,
