+                retry_policy: match routing.priority {
+                    RoutingPriority::Critical => RetryPolicy::Infinite,
+                    RoutingPriority::High => RetryPolicy::Count(5),
+                    RoutingPriority::Normal => RetryPolicy::Count(3),
+                    RoutingPriority::Low => RetryPolicy::None,
